field.expression:
                    select sum(FF.faltas) from
                    (select C1.fecha,
@hing:= (SELECT H.ingresoPremio from HORARIOHIST as H  where H.desdeFecha <= C1.fecha and H.dia = DAYOFWEEK(C1.fecha) order by H.desdeFecha DESC limit 1) as "hing",
@hegr:= (SELECT H.egresoPremio  from HORARIOHIST as H  where H.desdeFecha <= C1.fecha and H.dia = DAYOFWEEK(C1.fecha) order by H.desdeFecha DESC limit 1) as "hegr",

@h1:=(select H1.crc from FICHADAS as H1 where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__]  and TJT.fechaDesde <= C1.fecha order by fechaDesde DESC limit 1) and H1.fecha = C1.fecha and H1.borrado = 0 order by hora limit 0, 1) as "h1",
@h2:=(select H1.crc from FICHADAS as H1 where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__]  and TJT.fechaDesde <= C1.fecha order by fechaDesde DESC limit 1) and H1.fecha = C1.fecha and H1.borrado = 0 order by hora limit 1, 1) as "h2",
@h3:=(select H1.crc from FICHADAS as H1 where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__]  and TJT.fechaDesde <= C1.fecha order by fechaDesde DESC limit 1)  and H1.fecha = C1.fecha and H1.borrado = 0 order by hora limit 2, 1) as "h3",
@h4:=(select H1.crc from FICHADAS as H1 where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__]  and TJT.fechaDesde <= C1.fecha order by fechaDesde DESC limit 1) and H1.fecha = C1.fecha and H1.borrado = 0 order by hora limit 3, 1) as "h4",

@trabaj:=(ifnull(time_to_sec(timediff(@h2, @h1)), 0)+
         ifnull(time_to_sec(timediff(@h4, @h3)), 0)) / 3600,

@ideal:=ifnull(time_to_sec(timediff(@hegr, @hing)),0) / 3600,
ifnull((case when @trabaj >= @ideal then 0 when (@trabaj >= 2 and @trabaj < @ideal) then 0.5 when (@trabaj < 2 ) then 1 end), 0) as "faltas"

                    from GEN_CALENDAR as C1 left join FERIADOS ON FERIADOS.idFeriado = C1.fecha
        where
                          C1.fecha  >= '[__desde__]' and
                          C1.fecha  <= '[__hasta__]' and
        isnUll(FERIADOS.idFeriado)) as FF

                    select sum(FF.faltas) from
                    (select C1.fecha,
@hing:= (SELECT H.ingresoPremio from HORARIOHIST as H  where H.desdeFecha <= C1.fecha and H.dia = DAYOFWEEK(C1.fecha) order by H.desdeFecha DESC limit 1) as "hing",
@hegr:= (SELECT H.egresoPremio  from HORARIOHIST as H  where H.desdeFecha <= C1.fecha and H.dia = DAYOFWEEK(C1.fecha) order by H.desdeFecha DESC limit 1) as "hegr",

@h1:=(select H1.crc from FICHADAS as H1 where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__]  and TJT.fechaDesde <= C1.fecha order by fechaDesde DESC limit 1) and H1.fecha = C1.fecha and H1.borrado = 0 order by hora limit 0, 1) as "h1",
@h2:=(select H1.crc from FICHADAS as H1 where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__]  and TJT.fechaDesde <= C1.fecha order by fechaDesde DESC limit 1) and H1.fecha = C1.fecha and H1.borrado = 0 order by hora limit 1, 1) as "h2",
@h3:=(select H1.crc from FICHADAS as H1 where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__]  and TJT.fechaDesde <= C1.fecha order by fechaDesde DESC limit 1)  and H1.fecha = C1.fecha and H1.borrado = 0 order by hora limit 2, 1) as "h3",
@h4:=(select H1.crc from FICHADAS as H1 where H1.tarjeta = (SELECT TJT.tarjeta from PERSONAL_TARJETA as TJT where TJT.idPersona = [__idPersona__]  and TJT.fechaDesde <= C1.fecha order by fechaDesde DESC limit 1) and H1.fecha = C1.fecha and H1.borrado = 0 order by hora limit 3, 1) as "h4",

@trabaj:=(ifnull(time_to_sec(timediff(@h2, @h1)), 0)+
         ifnull(time_to_sec(timediff(@h4, @h3)), 0)) / 3600,

@ideal:=ifnull(time_to_sec(timediff(@hegr, @hing)),0) / 3600,
ifnull(case when (@trabaj >= 2 and @trabaj < @ideal) then 1 end, 0) as "faltas"

                    from GEN_CALENDAR as C1 left join FERIADOS ON FERIADOS.idFeriado = C1.fecha
        where
                          C1.fecha  >= '[__desde__]' and
                          C1.fecha  <= '[__hasta__]' and
        isnUll(FERIADOS.idFeriado)) as FF
